#!/usr/bin/env Rscript

# Helper R script to perform PCA on the merged peak quantification matrix generated by HOMER's annotatePeaks.pl


suppressPackageStartupMessages({
    library(ggplot2)
    library(ggrepel)
})

# 0. Get input matrix file
args <- commandArgs(trailingOnly = TRUE)
matrix_file <- args[1]

# 1. Read HOMER matrix
d <- read.table(matrix_file, sep = "\t", header = TRUE, quote = "",
                comment.char = "", check.names = FALSE)

# 2. Extract sample count columns (HOMER standard: first 19 cols are annotation metadata)
#    Column names after header cleaning should be bare sample IDs
all_cols   <- colnames(d)
data_cols  <- all_cols[20:length(all_cols)]

# Further strip any residual path/suffix left by HOMER (e.g. " Tag Count")
data_cols_clean <- sub("^tagdirs/", "", data_cols)
data_cols_clean <- sub(" .*", "", data_cols_clean)

mat <- d[, 20:length(all_cols), drop = FALSE]
colnames(mat) <- data_cols_clean
rownames(mat) <- d[, 1]

# Guard: stop with a clear message if no sample columns were found
if (ncol(mat) == 0) {
    stop("No sample columns found in HOMER matrix after column 19. ",
         "Check that annotatePeaks.pl ran with -d and that the header was cleaned correctly.\n",
         "Columns present: ", paste(all_cols, collapse = ", "))
}

# 3. Log transform
mat_log <- log2(mat + 1)

# 4. Filter low-variance peaks (bottom 10%), but guard against over-filtering
rv        <- apply(mat_log, 1, var)
threshold <- quantile(rv, 0.1)
mat_filt  <- mat_log[rv > threshold, , drop = FALSE]

if (nrow(mat_filt) == 0) {
    message("Variance filter removed all rows — falling back to unfiltered matrix.")
    mat_filt <- mat_log
}

# Guard: prcomp needs at least as many rows as columns
if (nrow(mat_filt) < ncol(mat_filt)) {
    stop("Not enough peaks (", nrow(mat_filt), ") to compute PCA across ",
         ncol(mat_filt), " samples. Check consensus peak calling output.")
}

# 5. PCA
pca_res <- prcomp(t(mat_filt), scale. = TRUE)
pct     <- round(100 * summary(pca_res)$importance[2, 1:2], 1)

pca_df            <- as.data.frame(pca_res$x[, 1:2])
pca_df$sample     <- rownames(pca_df)
pca_df$condition  <- sub("_.*", "", pca_df$sample)

# 6. Plot
p <- ggplot(pca_df, aes(x = PC1, y = PC2, colour = condition, label = sample)) +
    geom_point(size = 4) +
    geom_text_repel(size = 3.5) +
    labs(title = "PCA of Consensus Peak Quantification",
         x = paste0("PC1 (", pct[1], "%)"),
         y = paste0("PC2 (", pct[2], "%)")) +
    theme_bw(base_size = 11)

ggsave("pca_peaks.png", plot = p, width = 6, height = 5, dpi = 180)
